public class DTWKernel extends Kernel {
    private final double[][] table;
    private final double[] swap;

    @Builder
    public DTWKernel(double[][] arr1, double[][] arr2, double[] distance, double[][] table, double[] swap) {
        this.table = table;
        this.swap = swap;
        // ...其他初始化代码
    }

    @Override
    public void run() {
        int id = getGlobalId();
        distance[id] = d(arr1[id], arr2[id]);
    }

    // ... d 方法和其他实现
}

